    b = 1
    if n == 0:
        return a
    elif n == 1:
        return b
    else:
        for i in range(2,n+1):
            c = a + b
            a = b
            b = c
        return b

def binary_search(arr, target): 
    low = 0
    high = len(arr) - 1

    while low <= high:
        mid = (low + high) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] > target:
            high = mid - 1
        else:
            low = mid + 1

    return -1

class TwoStackQueue:
    def __init__(self):
        self.stack1 = []
        self.stack2 = []

    def isEmpty(self):
        return self.stack1 == [] and self.stack2 == []

    def enqueue(self, item):
        if not self.isFull():
            self.stack1.append(item)
            while self.stack2:
                self.stack1.append(self.stack2.pop())
        else:
            self.stack2.append(item)
            while self.stack1:
                self.stack2.append(self.stack1.pop())

    def dequeue(self):
        if not self.isEmpty():
            if self.stack1:
                return self.stack1.pop()
            else:
                self.stack2.pop()
        return None

    def peek(self):
        if not self.isEmpty():
            if self.stack1:
                return self.stack1[-1]
            else:
                return self.stack2[-1]
        return None

def common_elements(arr1, arr2):
    # Initialize a result array
    result = []

    # Iterate over the first array
    for i in range(len(arr1)):
        # Iterate over the second array
        for j in range(len(arr2)):
